using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still references c.Discriminator (preserved via HasDiscriminator config).
        // NOTE: EF9 Cosmos raw SQL now requires VALUE projection for entity queries.
        var sql = "SELECT VALUE c FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF9 Cosmos provider no longer supports sync I/O — use async.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

